#include<bits/stdc++.h>
using namespace std;
list<int>l1;
int main()
{
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++){
    	l1.push_back(i);
	}
    for(int i=0;i<n;i++){
        for(int j=0;j<m-1;j++){
        	  l1.push_back(l1.front());
        	  l1.pop_front();
        }
        cout<<l1.front()<<" ";
        l1.pop_front();
    }
}
